function kClosestPointsToOrigin(data) {
    const lines = data.trim().split('\n');
    const points = lines[0].split(' ').map((num, index) => index % 2 === 0 ? [parseInt(num), parseInt(lines[0].split(' ')[index + 1])] : null).filter(Boolean);
    const k = parseInt(lines[1]);

    const distances = points.map(point => {
        const distance = Math.sqrt(point[0] ** 2 + point[1] ** 2);
        return { point, distance };
    });

    distances.sort((a, b) => a.distance - b.distance);
    return distances.slice(0, k).map(item => item.point).flat();
}

