package main

import (
    "math"
    "sort"
)

func kClosestPointsToOrigin(data [][]int) [][]int {
    type point struct {
        x, y, dist int
    }

    points := make([]point, len(data))
    for i, p := range data {
        distance := p[0]*p[0] + p[1]*p[1]
        points[i] = point{p[0], p[1], distance}
    }

    sort.Slice(points, func(i, j int) bool {
        return points[i].dist < points[j].dist
    })

    result := make([][]int, 0)
    for i := 0; i < len(points); i++ {
        result = append(result, []int{points[i].x, points[i].y})
    }

    return result
}

