#include <queue>
#include <cmath>
using namespace std;
class Solution {
    public:
    vector<vector<int>> kClosestPointsToOrigin(vector<vector<int>>& data, int k) {
        auto comp = [](const pair<double, vector<int>>& a, const pair<double, vector<int>>& b) {
            return a.first < b.first;
        }
        ;
        priority_queue<pair<double, vector<int>>, vector<pair<double, vector<int>>>, decltype(comp)> maxHeap(comp);
        for (const auto& point : data) {
            double distance = sqrt(point[0] * point[0] + point[1] * point[1]);
            maxHeap.push({
                distance, point
            }
            );
            if (maxHeap.size() > k) {
                maxHeap.pop();
            }
        }
        vector<vector<int>> result;
        while (!maxHeap.empty()) {
            result.push_back(maxHeap.top().second);
            maxHeap.pop();
        }
        return result;
    }
}
