package main

import (
    "container/heap"
    "math"
)

type Point struct {
    x, y int
}

type MaxHeap []Point

func (h MaxHeap) Len() int           { return len(h) }
func (h MaxHeap) Less(i, j int) bool { return distance(h[i]) > distance(h[j]) }
func (h MaxHeap) Swap(i, j int)      { h[i], h[j] = h[j], h[i] }

func (h *MaxHeap) Push(x interface{}) {
    *h = append(*h, x.(Point))
}

func (h *MaxHeap) Pop() interface{} {
    old := *h
    n := len(old)
    x := old[n-1]
    *h = old[0 : n-1]
    return x
}

func distance(p Point) float64 {
    return math.Sqrt(float64(p.x*p.x + p.y*p.y))
}

func kClosestPointsToOrigin(data [][]int) [][]int {
    k := len(data)
    if k == 0 {
        return [][]int{}
    }

    h := &MaxHeap{}
    heap.Init(h)

    for _, point := range data {
        p := Point{x: point[0], y: point[1]}
        heap.Push(h, p)
        if h.Len() > k {
            heap.Pop(h)
        }
    }

    result := make([][]int, h.Len())
    for i := 0; i < h.Len(); i++ {
        p := heap.Pop(h).(Point)
        result[i] = []int{p.x, p.y}
    }

    return result
}

