public class Solution {
    public int[][] kClosestPointsToOrigin(int[][] data) {
        if (data == null || data.Length == 0) return new int[0][];
        int k = Math.Min(data.Length, 3); // Assuming k is 3 for this example
        var maxHeap = new SortedSet<(double distance, int[] point)>(Comparer<(double, int[])>.Create((a, b) => 
            a.distance == b.distance ? a.point[0].CompareTo(b.point[0]) : b.distance.CompareTo(a.distance)));

        foreach (var point in data) {
            double distance = Math.Sqrt(point[0] * point[0] + point[1] * point[1]);
            maxHeap.Add((distance, point));
            if (maxHeap.Count > k) {
                maxHeap.Remove(maxHeap.Max);
            }
        }

        int[][] result = new int[maxHeap.Count][];
        int index = 0;
        foreach (var item in maxHeap) {
            result[index++] = item.point;
        }
        return result;
    }
}
